### 3. WebSocket 无认证机制

**位置**: `src/dashboard/server.ts` (Line 119-161)

**问题描述**:
WebSocket 连接 `/api/ws` 没有任何身份验证，任何人都可以连接并接收实时数据或发送控制命令。

**风险评级**: ⚠️ **高危 (CVSS 8.2)**

```typescript
// src/dashboard/server.ts:120
fastify.get('/api/ws', { websocket: true }, (connection, req) => {
  // ❌ 没有身份验证
  logger.info('WebSocket client connected');
```

**修复建议**:

1. **实施 JWT 认证**
```typescript
import jwt from 'jsonwebtoken';

// WebSocket 认证中间件
fastify.get('/api/ws', { 
  websocket: true,
  onRequest: async (request, reply) => {
    try {
      // 从查询参数获取 token
      const token = request.query.token || 
                   request.headers['authorization']?.replace('Bearer ', '');

      if (!token) {
        throw new Error('Missing authentication token');
      }

      // 验证 JWT
      const decoded = jwt.verify(token, process.env.JWT_SECRET);
      request.user = decoded;
    } catch (error) {
      reply.code(401).send({ error: 'Unauthorized' });
      throw new Error('Unauthorized');
    }
  }
}, (connection, req) => {
  const user = (req as any).user;
  logger.info({ userId: user.id }, 'WebSocket client authenticated');
  // ...
});
```

2. **使用 session 认证**
```typescript
import { createClient } from 'redis';

const redisClient = createClient({ url: process.env.REDIS_URL });

// WebSocket 认证
fastify.get('/api/ws', { websocket: true }, async (connection, req) => {
  const sessionId = req.query.sessionId;

  // 验证 session
  const session = await redisClient.get(`session:${sessionId}`);
  if (!session) {
    connection.socket.close(1008, 'Unauthorized');
    return;
  }

  const user = JSON.parse(session);
  connection.socket.userId = user.id;
});
```

3. **实施速率限制**
```typescript
import rateLimit from 'express-rate-limit';

const wsRateLimiter = new Map();

function checkRateLimit(userId: string): boolean {
  const now = Date.now();
  const userLimit = wsRateLimiter.get(userId) || { count: 0, resetAt: now + 60000 };

  if (now > userLimit.resetAt) {
    userLimit.count = 0;
    userLimit.resetAt = now + 60000;
  }

  userLimit.count++;
  wsRateLimiter.set(userId, userLimit);

  return userLimit.count <= 60; // 每分钟最多 60 个连接
}
```

