### 10. 缺少输入验证

**位置**: 
- `src/main.ts` (Line 298-318)
- `src/auto-iteration.ts` (Line 240-250)

**问题描述**:
命令行参数和用户输入未经验证直接使用。

**修复建议**:

```typescript
import { z } from 'zod';

const CommandLineSchema = z.object({
  requirement: z.string().max(10000).optional(),
  interval: z.number().int().min(10).max(3600).default(60),
  max: z.number().int().min(0).max(1000).default(0),
  autoPush: z.boolean().default(true),
  file: z.string().refine(
    (val) => {
      // 验证路径在项目目录内
      const resolved = path.resolve(val);
      return resolved.startsWith(process.cwd());
    },
    'File path must be within project directory'
  ).optional()
});

function parseCommandLine(args: string[]) {
  const params = {
    requirement: getArgValue(args, '--requirement'),
    interval: parseInt(getArgValue(args, '--interval') || '60'),
    max: parseInt(getArgValue(args, '--max') || '0'),
    autoPush: !args.includes('--no-push'),
    file: getArgValue(args, '--file')
  };

  return CommandLineSchema.parse(params);
}
```

