// ✅ 安全写法 - 使用参数化
import { spawnSync } from 'child_process';

function gitCommit(cwd: string, message: string) {
  // 1. 验证和净化输入
  const sanitized = message
    .replace(/[^\w\s\u4e00-\u9fa5.,!?-]/g, '') // 只允许安全字符
    .substring(0, 200); // 限制长度

  // 2. 使用参数化而非字符串拼接
